package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import com.google.gson.internal.ReflectionAccessFilterHelper;

class ReflectionAccessFilterHelperTest {

  private AccessibleObject accessibleObjectMock;
  private Object targetObject;
  private Object accessCheckerMock;

  @BeforeEach
  void setUp() throws Exception {
    accessibleObjectMock = mock(AccessibleObject.class);
    targetObject = new Object();

    // Use reflection to access the private static AccessChecker.INSTANCE field and replace it with a mock
    Class<?> accessCheckerClass = Class.forName("com.google.gson.internal.ReflectionAccessFilterHelper$AccessChecker");
    accessCheckerMock = mock(accessCheckerClass);

    Field instanceField = accessCheckerClass.getDeclaredField("INSTANCE");
    instanceField.setAccessible(true);

    // Remove final modifier from INSTANCE field if needed
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(instanceField, instanceField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    instanceField.set(null, accessCheckerMock);
  }

  @Test
  void testCanAccess_returnsTrue_whenAccessCheckerReturnsTrue() throws Exception {
    // Use reflection to invoke canAccess on the mock
    when(accessCheckerMock.getClass().getMethod("canAccess", AccessibleObject.class, Object.class)
        .invoke(accessCheckerMock, accessibleObjectMock, targetObject)).thenReturn(true);

    // Because the above won't work directly with when(), use Mockito's doReturn().when() with spy
    doReturn(true).when(accessCheckerMock).getClass()
        .getMethod("canAccess", AccessibleObject.class, Object.class)
        .invoke(accessCheckerMock, accessibleObjectMock, targetObject);

    // Instead, use Mockito's doReturn on the mock with reflection proxy:
    // But this is complicated, better use Mockito's 'when' with a cast
    // So we cast to Object and use Mockito's when with reflection proxy:
    // To simplify, create a proxy interface for AccessChecker is complicated.
    // So instead, use Mockito's Answer to handle invocation.

    // Alternative: Use Mockito's when with reflection proxy:
    // But here, let's use Mockito's doAnswer for canAccess method:

    // Reset accessCheckerMock to a spy with canAccess method mocked:
    reset(accessCheckerMock);
    when(accessCheckerMock.getClass().getMethod("canAccess", AccessibleObject.class, Object.class)
        .invoke(accessCheckerMock, accessibleObjectMock, targetObject)).thenReturn(true);

    // This is complicated; better to use Mockito's doAnswer with reflection:
    // So we create a spy with the canAccess method stubbed:

    // Instead, use Mockito's doAnswer on the mock's canAccess method via reflection:
    // But since it's private class, let's create a proxy interface to call canAccess:

    // So let's create a small interface to cast the mock:

    interface AccessCheckerInterface {
      boolean canAccess(AccessibleObject ao, Object o);
    }

    AccessCheckerInterface proxy = (AccessCheckerInterface) accessCheckerMock;

    when(proxy.canAccess(accessibleObjectMock, targetObject)).thenReturn(true);

    boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
    assertTrue(result);
  }

  @Test
  void testCanAccess_returnsFalse_whenAccessCheckerReturnsFalse() throws Exception {
    interface AccessCheckerInterface {
      boolean canAccess(AccessibleObject ao, Object o);
    }
    AccessCheckerInterface proxy = (AccessCheckerInterface) accessCheckerMock;

    when(proxy.canAccess(accessibleObjectMock, targetObject)).thenReturn(false);

    boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
    assertFalse(result);
  }

  @Test
  void testPrivateConstructor() throws Exception {
    var constructor = ReflectionAccessFilterHelper.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    Object instance = constructor.newInstance();
    assertNotNull(instance);
  }
}
